// --- ВСПОМОГАТЕЛЬНАЯ ФУНКЦИЯ ДЛЯ ПРОВЕРКИ АЧИВОК ---
function checkConsecutiveDays(dailyStats, neededDays) {
    if (!dailyStats) return false;
    let dates = Object.keys(dailyStats).sort((a,b) => new Date(b) - new Date(a));
    if (dates.length < neededDays) return false;
    for(let i = 0; i < neededDays - 1; i++) {
        let d1 = new Date(dates[i]); 
        let d2 = new Date(dates[i+1]);
        let diffTime = Math.abs(d1 - d2); 
        let diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 
        if (diffDays > 1) return false;
    }
    return true;
}

